powershell -NoProfile -Command "$pids = ((Get-NetTCPConnection -LocalPort 3000,3001,3002 -State Listen -ErrorAction SilentlyContinue).OwningProcess | Select-Object -Unique); if($pids){ $pids | ForEach-Object { Stop-Process -Id $_ -Force -ErrorAction SilentlyContinue }}; Get-Process node -ErrorAction SilentlyContinue | Stop-Process -Force -ErrorAction SilentlyContinue; Remove-Item 'E:\CONFIT\frontend\.next' -Recurse -Force -ErrorAction SilentlyContinue; $env:NEXT_TELEMETRY_DISABLED='1'; cd 'E:\CONFIT\frontend'; npm run dev"
